import React, { useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  FaBook,
  FaChalkboardTeacher,
  FaClipboardList,
  FaComments,
  FaHome,
  FaListAlt,
  FaSignOutAlt,
  FaTasks,
  FaUserCircle
} from 'react-icons/fa';
import { AuthContext } from '../context/AuthContext';
import styles from '../styles/inlineStyles';

const Navigation = () => {
  const { user, logout } = useContext(AuthContext);
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const navActionStyle = {
    ...styles.navLink,
    display: 'inline-flex',
    alignItems: 'center',
    gap: '6px',
    background: 'transparent',
    border: 'none',
    padding: '8px 12px',
    font: 'inherit'
  };

  const iconOnlyStyle = {
    ...styles.navLink,
    display: 'inline-flex',
    alignItems: 'center',
    justifyContent: 'center',
    gap: '0',
    background: 'transparent',
    border: 'none',
    padding: '8px',
    font: 'inherit',
    fontSize: '18px'
  };

  return (
    <nav style={{ ...styles.nav, display: 'flex', flexDirection: 'column', minHeight: '100vh' }}>
      {/* Top Left: User Profile and Logout Icons */}
      {user && (
        <div style={{ display: 'flex', gap: '10px', alignItems: 'center', padding: '15px', justifyContent: 'flex-start' }}>
          <button type="button" onClick={() => navigate('/profile')} style={iconOnlyStyle} title={user.name}>
            <FaUserCircle />
          </button>
          <button onClick={handleLogout} style={{ ...iconOnlyStyle, color: '#ff6b6b' }} title="Logout">
            <FaSignOutAlt />
          </button>
        </div>
      )}

      {/* Center: Logo and Brand */}
      <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <h2
          style={{ margin: 0, cursor: 'pointer', fontSize: '20px', color: 'white', display: 'inline-flex', alignItems: 'center', gap: '8px' }}
          onClick={() => navigate('/dashboard')}
        >
          <img
            src="/image/logo.jpeg"
            alt="Learn Bridge logo"
            style={{ height: '65px', width: 'auto', display: 'block' }}
          />
          Learn bridge
        </h2>
      </div>

      {/* Bottom Right: Navigation Menu */}
      <div style={{ display: 'flex', gap: '20px', alignItems: 'center', flexWrap: 'wrap', padding: '15px', justifyContent: 'flex-end' }}>
        {user && (
          <>
            <button type="button" onClick={() => navigate('/dashboard')} style={navActionStyle}>
              <FaHome /> Home
            </button>

            {user.role === 'student' && (
              <>
                <button type="button" onClick={() => navigate('/study-planner')} style={navActionStyle}>
                  <FaTasks /> Planner
                </button>
                <button type="button" onClick={() => navigate('/materials')} style={navActionStyle}>
                  <FaBook /> Materials
                </button>
                <button type="button" onClick={() => navigate('/questions')} style={navActionStyle}>
                  <FaComments /> Q&A
                </button>
                <button type="button" onClick={() => navigate('/mcq')} style={navActionStyle}>
                  <FaClipboardList /> MCQ
                </button>
                <button type="button" onClick={() => navigate('/appointments')} style={navActionStyle}>
                  <FaChalkboardTeacher /> Sessions
                </button>
                <button type="button" onClick={() => navigate('/progress')} style={navActionStyle}>
                  <FaListAlt /> Progress
                </button>
              </>
            )}

            {user.role === 'tutor' && (
              <>
                <button type="button" onClick={() => navigate('/subjects')} style={navActionStyle}>
                  <FaListAlt /> Subjects
                </button>
                <button type="button" onClick={() => navigate('/materials')} style={navActionStyle}>
                  <FaBook /> Materials
                </button>
                <button type="button" onClick={() => navigate('/questions')} style={navActionStyle}>
                  <FaComments /> Q&A
                </button>
                <button type="button" onClick={() => navigate('/sessions')} style={navActionStyle}>
                  <FaChalkboardTeacher /> Sessions
                </button>
              </>
            )}
          </>
        )}
      </div>
    </nav>
  );
};

export default Navigation;
